#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (arr[i] % 4 != 0) {
                count++;
            }
        }
        if (count % 2 == 1) {
            int flag = 0;
            for (int i = 0; i < n; i++) {
                if (arr[i] % 4 == 0) {
                    flag = 1;
                    break;
                }
            }
            if (flag == 0) {
                printf("-1\n");
            } else {
                printf("%d\n", count / 2);
            }
        } else {
            printf("%d\n", count / 2);
        }
    }
    return 0;
}

