import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = sc.nextInt();
            }
            int count = 0;
            for (int i = 0; i < n; i++) {
                if (arr[i] % 4 != 0) {
                    count++;
                }
            }
            if (count % 2 == 1) {
                int flag = 0;
                for (int i = 0; i < n; i++) {
                    if (arr[i] % 4 == 0) {
                        flag = 1;
                        break;
                    }
                }
                if (flag == 0) {
                    System.out.println(-1);
                } else {
                    System.out.println(count / 2);
                }
            } else {
                System.out.println(count / 2);
            }
        }
